var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"선배!","JPN":"先輩！","ENG":"Shiyoon!","TWN":"前輩！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"선배, 정신차려! 선배!!","JPN":"先輩、しっかりして！　先輩！！","ENG":"Wake up! Shiyoon!!","TWN":"前輩！你振作一點！！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미…… 미나 양……?","JPN":"ミ……ミナさん……？","ENG":"M-Mina?","TWN":"米……米娜……？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"다행이다. 무사해서.","JPN":"よかった。無事だったのね。","ENG":"Thank goodness. You're all right!","TWN":"幸好你沒事！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"조금만 기다려. 내가 풀어 줄게.","JPN":"少しだけ待ってて。私が解いてあげる。","ENG":"Give me just a second. I'll untie you.","TWN":"等一下，我現在就替你鬆綁！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"다른 사람은…… 여기 다른 사람은 없었나요?","JPN":"他の人は……ここに他の人はいませんでした？","ENG":"Did you see… anyone else here?","TWN":"其他人呢……這裡沒有其他人嗎？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"다른 사람? 선배 말고 또 누가 갇혀 있던 거야?","JPN":"他の人？　先輩以外に他の人が閉じ込められていたの？","ENG":"Someone else? Was there someone else locked up in here?","TWN":"其他人？除了前輩還有其他人被關在這裡嗎？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"내가 왔을 때는 선배밖에 없었어.","JPN":"私が着いた時は先輩しかいなかったよ。","ENG":"I didn't see anyone but you when I got here.","TWN":"我來的時候只有看到前輩而已。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"혹시 납치범이나 그 일당들을 말하는 거야?","JPN":"もしかして誘拐犯とかその一味のこと？","ENG":"Are you talking about the guys who abducted you?","TWN":"還是你是指綁架你的人跟他的同夥？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그러고 보니 궁금한 게 있는데…… 선배를 습격한 게 정말 레이 선배였어?","JPN":"そういえば気になることがあるんだけど……先輩を襲ったのは本当にレイ先輩だったの？","ENG":"Which reminds me… Was it really Ray who ambushed you?","TWN":"說到這個，我想知道……偷襲前輩的人真的是雷伊前輩嗎？　"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"대체 왜 레이 선배가 이런 짓을 저지른 거야?","JPN":"いったいなんでレイ先輩はこんなことをしたの？","ENG":"Why would Ray do such a thing?","TWN":"雷伊前輩為什麼要這麼做?　"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그리고 알렌 선생님은? 그 사람도 이 일에 관련되어 있는 거야?","JPN":"あとアレン先生は？　あの人もこの事件に関係してるの？","ENG":"And what about Mr. Birmingham? Is he tied up in this as well?","TWN":"還有艾倫老師，他也和這件事有關嗎？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"……미안해요. 지금은 자세히 대답드리기가 어렵겠네요.","JPN":"……すみません、今詳しく答えるのはちょっと難しいですね。","ENG":"…Sorry. I'm not sure I can give you answers right now.","TWN":"……不好意思，我現在無法回答這麼多問題。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"피를 많이 흘렸더니, 조금 어지러워서…….","JPN":"血を流しすぎて、少し目まいが……","ENG":"I'm pretty dizzy from the blood loss…","TWN":"我血流太多，現在頭有點暈……"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"미, 미안. 선배도 몸이 정상은 아닐 텐데…….","JPN":"ご、ごめん。先輩も辛い状況なのに……","ENG":"S-sorry. It must be rough for you…","TWN":"對…對不起！都忘記你現在是傷患……"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"일단은 안전한 곳으로 가자. 걸을 수 있겠어?","JPN":"とりあえず安全な場所に行こう。歩けそう？","ENG":"Let's get you somewhere safe first. Think you can walk?","TWN":"我們先移動到安全的地方吧？你還能走嗎？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"……하하, 쉽진 않네요.","JPN":"……ハハ、厳しそうです。","ENG":"Haha… I'm not so sure about that.","TWN":"……哈哈，有點難。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"오랫동안 묶여 있어서 그런가 보네.","JPN":"長い間縛られていたせいだね。","ENG":"I guess you've been tied up for too long.","TWN":"可能是因為身體長時間被綁住，才會腳麻不能動。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"기운내. 금방 나아질 거야. 선배는 강하잖아.","JPN":"元気出して、すぐよくなるよ。先輩は強いからね。","ENG":"Don't worry. You'll get better in no time. You're strong.","TWN":"沒事的，很快就會好的，前輩很強的！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"부축해 줄게. 이쪽으로 기대.","JPN":"支えてあげる。こっちに寄りかかって。","ENG":"I'll help you out. Lean on me.","TWN":"我扶你走！你靠我這邊。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이거 참…… 미나 양에게 짐이 되는 날이 올 줄은 몰랐네요.","JPN":"やれやれ……ミナさんに支えてもらう日が来るとは。","ENG":"Oh my… I never imagined I'd be a burden on you like this.","TWN":"真是的……沒想到我會有成為米娜負擔的一天。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"선배로서 좀 부끄러워지는데요……","JPN":"先輩として少し恥ずかしくなります……","ENG":"This is kind of embarrassing, really…","TWN":"我這樣算什麼前輩……"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"뭐, 뭘 이런 걸로 그래.","JPN":"こ、これぐらいのことでそんなこと言わないで。","ENG":"Oh, don't worry about it.","TWN":"這沒什麼啦！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"평소에 빚진 만큼 갚는 거야. 신경 꺼.","JPN":"普段お世話になっている分、恩返ししているだけだから気にしないで。","ENG":"I'm just returning all the favors you did for me. Don't let it bother you.","TWN":"我平常欠你那麼多，總該還一點吧！沒事的！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그러고 보니 미나 양도 몸이 피투성이네요.","JPN":"そういえばミナさんも血まみれですね。","ENG":"Come to think of it, you're all covered in blood yourself.","TWN":"我現在才看到，米娜你也有受傷！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"……괜찮은 건가요?","JPN":"……大丈夫ですか？","ENG":"Are you all right?","TWN":"……你沒事吧？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"응?","JPN":"うん？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"아, 그게……. 여기 오는 길에 꽤 난폭한 녀석이 길을 막고 있었거든.","JPN":"ああ、それが……途中でかなり乱暴な人に出くわしてね。","ENG":"Oh, you see… There was a pretty mean jerk I had to deal with on the way.","TWN":"哦～這個喔……因為來的路上有幾個凶狠的傢伙擋住去路，"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"조금 다치긴 했는데, 별거 아니야. 문제 없어……","JPN":"ちょっとケガはしているけど、大したことないよ。問題ない……","ENG":"I've got a few scratches, but it's nothing. No problem at all…","TWN":"是有受點小傷。沒事啦！我沒問題……"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":" 아얏!","JPN":"痛っ！","ENG":" Ow!","TWN":" 唉唷！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"아, 아니. 약간은 문제가 있을지도…….","JPN":"い、いや。少しは問題あるかも……","ENG":"T-then again… Maybe there's a slight problem…","TWN":"欸，可能有點問題……"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"하지만 이런 걸로 엄살 부릴 상황은 아니잖아. 안 그래?","JPN":"でもこの程度で弱音を吐く状況じゃないしね、そうでしょ？","ENG":"But I was never one for whining over something like this. Am I right?","TWN":"不過現在不是裝柔弱的時候！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"서윤이랑 학생회장이 밖에서 기다리고 있을 거야.","JPN":"シズカと生徒会長が外で待っているよ。","ENG":"Seo Yoon and the girls from the Academy should be waiting outside.","TWN":"徐芸和學生會長都在外面等我們。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"다들 선배를 걱정해서 구하러 왔거든.","JPN":"みんな先輩のことが心配で助けにきたの。","ENG":"They all came to rescue you with me.","TWN":"大家都很擔心前輩，說要一起來救你。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"지금은 통신이 두절되긴 했는데…….","JPN":"今は通信が切れているけど……","ENG":"Although we lost comms for now…","TWN":"雖然現在訊號不通……"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양, 앞을 봐요.","JPN":"ミナさん、前を見てください。","ENG":"Mina, look. In front of us.","TWN":"米娜，注意前面！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"응? 앞에 뭐라도 있어?","JPN":"うん？　なんかあるの？","ENG":"Hm? Is there something there?","TWN":"嗯？前面有東西嗎？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_DARK_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"저건…….","JPN":"あれは……","ENG":"What the…","TWN":"那是……"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"내 착각이 아니라면 선배랑 엄청 닮은 것 같은데…… 적은 아니겠지?","JPN":"私の見間違いじゃなければ先輩にとても似ている気がするけど……敵じゃないよね？","ENG":"Is it me or does that guy look just like you? It's not… an enemy, is it?","TWN":"我沒眼花的話，那個人長得跟前輩好像……應該不是敵人吧？"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"……유감이지만 적일 겁니다.","JPN":"……残念ながら敵です。","ENG":"Regrettably, I think it is.","TWN":"……很遺憾，他應該是敵人沒錯。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"제 피를 뽑아서 어디에 쓰나 했더니…… 저런 걸 만들고 있었군요.","JPN":"僕の血を抜き取って何に使ったのかと思ったら……あんなモノを作っていたのですね。","ENG":"I was wondering what they drew all my blood for… I guess they were creating that thing.","TWN":"我還想說抽我這麼多血是要幹嘛……原來就是他。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"피를 뽑아?","JPN":"血を抜き取る！？","ENG":"They drew your blood?","TWN":"抽血？"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"네. 안타깝지만, 그래서 전 지금 미나 양을 도와드리기 어렵겠어요.","JPN":"はい。申し訳ないですが、今の僕はミナさんの力になれそうな状態ではありません。","ENG":"Yes. And as such, I'm afraid I won't be of much help to you right now.","TWN":"對，所以很抱歉，現在的我可能無法幫你什麼忙。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"걱정 마. 나도 예전보다는 강해졌으니까.","JPN":"心配しないで、私も前より強くなったから。","ENG":"Don't worry. I'm a lot stronger than I used to be.","TWN":"別擔心！我比以前強很多好嗎！"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"여기서 잠깐 쉬고 있어. 금방 해치우고 올게.","JPN":"ここで少し休んでいて。さっさとやっつけてくるね。","ENG":"Get some rest here. I'll go take care of this in no time.","TWN":"你先在這裡稍作休息，我去處理他，很快就回。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그런데 잠깐, 선배의 피로 만들었다며? 해치워도 괜찮은 거야?","JPN":"でも待って、先輩の血で作ったんでしょ？　やっつけていいの？","ENG":"By the way, did you say they made that thing with your blood? Is it okay if I get rid of it?","TWN":"可是，你說他是用你的血所造的，那我殺掉他沒關係嗎？"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"……괜찮으니까 주저하지 마세요.","JPN":"……平気なので躊躇しないでください。","ENG":"…It's fine. Don't hesitate.","TWN":"……沒關係，你千萬不要手下留情。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"저건 저한테서 추출한 용혈의 힘으로 만들어낸 존재일 거예요.","JPN":"あれは僕から抽出した龍血の力で作り出した存在です。","ENG":"That thing was probably created from the Dragon Blood they extracted from me.","TWN":"他是用我體內的龍血所造的，"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"제 입으로 말하긴 그렇지만…… 아마 강할 겁니다.","JPN":"自分の口で言うのもなんですが……おそらく強いでしょう。","ENG":"At the risk of sounding conceited… It's probably quite formidable.","TWN":"由我自己來說有點害羞……但他應該滿強的。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그러니까 조심하세요, 미나 양.","JPN":"だからご用心を、ミナさん。","ENG":"So be careful, Mina.","TWN":"米娜，你自己要小心。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"……응. 내게 맡겨.","JPN":"……うん、任せて。","ENG":"…Got it. You can count on me.","TWN":"……嗯，包在我身上"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};